const item = $input.first().json;
let cmd = '', chatId = '', src = '', fileId = '', fileType = '';

if (item.message) {
  const msg = item.message;
  cmd = (msg.text || msg.caption || '').trim();
  chatId = String(msg.chat.id);
  src = 'telegram';
  if (msg.video) { fileId = msg.video.file_id; fileType = 'video'; }
  else if (msg.document) { fileId = msg.document.file_id; fileType = 'document'; }
  else if (msg.photo) { fileId = msg.photo[msg.photo.length-1].file_id; fileType = 'photo'; }
} else if (item.callback_query) {
  cmd = (item.callback_query.data || '').trim();
  chatId = String(item.callback_query.message.chat.id);
  src = 'telegram_callback';
} else if (item.Body) {
  cmd = (item.Body || '').trim();
  chatId = item.From || '';
  src = 'whatsapp';
} else if (item.entry) {
  const msg = item.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
  cmd = (msg?.text?.body || '').trim();
  chatId = msg?.from || '';
  src = 'whatsapp_cloud';
} else {
  cmd = 'CREATE'; chatId = '8370599696' || ''; src = 'schedule';
}

const cmdUpper = cmd.toUpperCase();
let action = 'HELP', customTopic = '', niche = 'general', editInstructions = '';
let lang = '', voicetestTopic = '', dramaTitle = '', seriesName = '', seriesEp = '';
let thumbnailPick = 0, qualityMode = 'normal', budgetMode = 'auto';
let modelAction = '', modelName = '', modelScene = '';

if (fileId && fileType === 'video') {
  action = 'EDIT_MY_VIDEO';
  editInstructions = cmdUpper.startsWith('EDIT:') ? cmd.replace(/EDIT:/i, '').trim() : 'enhance and make viral';
}
else if (['CREATE','GO','MAKE','AUTO'].includes(cmdUpper)) { action = 'CREATE'; }
else if (cmdUpper.startsWith('TOPIC:')) { action = 'CREATE'; let t = cmd.replace(/TOPIC:/i,'').trim(); const qm = t.match(/\s+QUALITY:(HIGH|NORMAL|LOW)$/i); if (qm) { qualityMode = qm[1].toLowerCase(); t = t.replace(/\s+QUALITY:(HIGH|NORMAL|LOW)$/i,'').trim(); } customTopic = t; }
else if (cmdUpper.startsWith('NICHE:')) { action = 'CREATE'; niche = cmd.replace(/NICHE:/i,'').trim(); }
else if (cmdUpper === 'QUALITY:HIGH' || cmdUpper === 'QUALITY:HIGH CREATE') { action = 'CREATE'; qualityMode = 'high'; }
else if (cmdUpper === 'BUDGET:FREE' || cmdUpper === 'BUDGET:FREE CREATE') { action = 'CREATE'; budgetMode = 'free'; }
else if (cmdUpper.startsWith('BUDGET:FREE TOPIC:')) { action = 'CREATE'; budgetMode = 'free'; customTopic = cmd.replace(/BUDGET:FREE TOPIC:/i,'').trim(); }
else if (cmdUpper === 'LANG:HINDI' || cmdUpper === 'LANG:HINDI CREATE') { action = 'LANG_HINDI'; lang = 'hindi'; }
else if (cmdUpper.startsWith('LANG:HINDI TOPIC:')) { action = 'LANG_HINDI'; lang = 'hindi'; customTopic = cmd.replace(/LANG:HINDI TOPIC:/i,'').trim(); }
else if (cmdUpper === 'LANG:SPANISH CREATE' || cmdUpper === 'LANG:SPANISH') { action = 'CREATE'; lang = 'spanish'; }
else if (cmdUpper.startsWith('DRAMA:')) { action = 'DRAMA'; dramaTitle = cmd.replace(/DRAMA:/i,'').trim(); }
else if (cmdUpper.startsWith('SERIES:')) {
  action = 'DRAMA';
  const m = cmd.match(/SERIES:\s*(.+?)\s+EP(\d+)/i);
  if (m) { seriesName = m[1]; seriesEp = m[2]; }
  dramaTitle = cmd.replace(/SERIES:/i,'').trim();
}
else if (cmdUpper.startsWith('VOICETEST:')) { action = 'VOICETEST'; voicetestTopic = cmd.replace(/VOICETEST:/i,'').trim() || 'ancient india'; }
else if (cmdUpper === 'VOICE REPORT') { action = 'VOICE_REPORT'; }
else if (cmdUpper.startsWith('THUMBNAIL:')) { action = 'THUMBNAIL_PICK'; thumbnailPick = parseInt(cmd.replace(/THUMBNAIL:/i,'').trim()) || 1; }
else if (cmdUpper === 'STATUS') { action = 'STATUS'; }
else if (cmdUpper === 'PAUSE') { action = 'PAUSE'; }
else if (cmdUpper === 'RESUME') { action = 'RESUME'; }
else if (cmdUpper === 'COST') { action = 'COST'; }
else if (cmdUpper === 'SECURITY LOG') { action = 'SECURITY_LOG'; }
else if (cmdUpper === 'PUBLISH' || cmdUpper === 'YES') { action = 'PUBLISH'; }
else if (cmdUpper === 'REJECT' || cmdUpper === 'NO') { action = 'REJECT'; }
else if (cmdUpper.startsWith('EDIT:')) { action = 'EDIT'; editInstructions = cmd.replace(/EDIT:/i,'').trim(); }
else if (cmdUpper === 'HELP' || cmdUpper === 'START' || cmdUpper === '/START') { action = 'HELP'; }
else if (cmdUpper.startsWith('MODEL:')) {
  action = 'MODEL';
  const modelStr = cmd.replace(/MODEL:/i, '').trim();
  if (!modelStr || modelStr.toUpperCase() === 'LIST') {
    modelAction = 'LIST'; modelName = ''; modelScene = '';
  } else {
    const nameMatch = modelStr.match(/^(\w+)\s*(.*)/);
    modelName = (nameMatch ? nameMatch[1] : modelStr).toUpperCase();
    modelScene = nameMatch ? (nameMatch[2] || modelStr) : modelStr;
    modelAction = 'GENERATE';
  }
}

return [{ json: { action, cmd, cmdUpper, customTopic, niche, chatId, src, fileId, fileType, editInstructions, lang, voicetestTopic, dramaTitle, seriesName, seriesEp, thumbnailPick, qualityMode, budgetMode, modelAction, modelName, modelScene, ts: new Date().toISOString() } }];

const item = $input.first().json;
const chatId = String(item.chatId || '');
const ALLOWED_ID = '8370599696';
const src = item.src || '';

const stored = $getWorkflowStaticData('global');
if (!stored.securityLog) stored.securityLog = [];
if (!stored.dailyCount) stored.dailyCount = {};
if (stored.paused === undefined) stored.paused = false;
if (!stored.monthlyCost) stored.monthlyCost = 0;
if (!stored.costLog) stored.costLog = [];

const logEntry = { ts: new Date().toISOString(), chatId, src, action: item.action, cmd: item.cmd };

if (stored.paused && item.action !== 'RESUME' && item.action !== 'STATUS') {
  logEntry.blocked = true; logEntry.reason = 'workflow_paused';
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'workflow_paused' } }];
}

if (stored.monthlyCost > 100 && item.action === 'CREATE') {
  logEntry.blocked = true; logEntry.reason = 'monthly_budget_exceeded';
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'monthly_budget_exceeded', sendAlert: true } }];
}

if ((src === 'telegram' || src === 'telegram_callback') && chatId !== ALLOWED_ID) {
  logEntry.blocked = true; logEntry.reason = 'unauthorized_user'; logEntry.alert = true;
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'unauthorized_user', sendAlert: true } }];
}

const today = new Date().toISOString().split('T')[0];
if (!stored.dailyCount[today]) stored.dailyCount[today] = 0;

if (item.action === 'CREATE' && stored.dailyCount[today] >= 10) {
  logEntry.blocked = true; logEntry.reason = 'rate_limit';
  stored.securityLog.unshift(logEntry);
  if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);
  return [{ json: { ...item, blocked: true, blockReason: 'rate_limit_10_per_day' } }];
}

if (item.action === 'CREATE') stored.dailyCount[today]++;

logEntry.blocked = false;
stored.securityLog.unshift(logEntry);
if (stored.securityLog.length > 100) stored.securityLog = stored.securityLog.slice(0,100);

return [{ json: { ...item, blocked: false, todayCount: stored.dailyCount[today] || 0 } }];

