}

const msg = selectedUrl
  ? `Thumbnail ${pick} selected! It will be used when you PUBLISH.\n\nPreview: ${selectedUrl}`
  : `No pending video found. Create a video first, then pick thumbnail.`;

return [{ json: { ...data, selectedThumbnailUrl: selectedUrl, selectedThumb: pick, thumbnailPickMsg: msg } }];

const d = $input.first().json;
