const raw = $input.first().json;
const txt = raw.content?.[0]?.text || '{}';
let trend = {};
try { const m = txt.match(/\{[\s\S]*\}/); trend = m ? JSON.parse(m[0]) : {}; } catch(e) {}

if (!trend.trend_score) trend = {
  is_trending: true,
