const d = $input.first().json;
const ANT_KEY = 'YOUR_ANTHROPIC_API_KEY';

const topic = d.customTopic || (d.trend && d.trend.recommended_topic) || d.niche || (d.memory && d.memory.bestNiche) || 'South Asian history';
const channel = (d.memory && d.memory.channelName) || 'Empires Untold';
const style = (d.memory && d.memory.preferredStyle) || 'cinematic documentary';
const lang = d.lang || 'english';
const quality = d.qualityMode || 'normal';
const avoidList = JSON.stringify((d.memory && d.memory.avoidRepeat) || []);

const systemPrompt = 'You are an elite viral content researcher and scriptwriter for South Asian history YouTube. Use the exact formula proven by MagnatesMedia, ColdFusion, and MrBeast. Return ONLY valid JSON, no markdown.';

const userPrompt = 'Create a complete viral 55-60 second video package for "' + topic + '".\nChannel: ' + channel + ' | Style: ' + style + ' | Language: ' + lang + ' | Quality: ' + quality + '\nAvoid repeating: ' + avoidList + '\n\nSCRIPT STRUCTURE (non-negotiable):\n\nHOOK (0-7s) - THE MORAL CONTRACT: One shocking fact with SPECIFIC NUMBERS. Immediate curiosity gap. NEVER answer the question immediately.\nExamples: "They burned the evidence. Here is what they found anyway." | "This emperor killed 40 million people. Nobody talks about him." | "The British stole 45 TRILLION dollars from India. Here is the proof."\n\nOPEN LOOP (7-15s): Promise what they will learn WITHOUT revealing it yet.\n\nSTAKES ESCALATION throughout: Higher every 60-90s. Problem -> Bigger Problem -> Shocking Twist -> Devastating Revelation -> Payoff.\n\nMICRO-CLIFFHANGERS every 60-90s in script: "Coming up the document they tried to destroy..." or "But here is what makes this even more disturbing..." or "The answer changes everything we thought we knew..."\n\nPAYOFF at 85% mark. CTA: "Subscribe because this is just one chapter." CLIFFHANGER ENDING: tease next video.\n\nPOST-WATCH SATISFACTION last 10s: shocked, informed, angry, or proud. End: "Share this because most people will never know this."\n\nTITLE FORMULA - pick highest CTR:\nA: "[Specific Number] [Shocking Thing] About [Topic] Nobody Talks About"\nB: "The [Adjective] Truth About [Topic] They Do Not Want You To Know"\nC: "How [Person/Empire] [Did Something Shocking] And Nobody Stopped Them"\n\nQUALITY SCORING - if total below 30 rewrite and rescore until 30+:\nhook_score /10: STOP scrolling in 2 seconds?\nviral_score /10: Will people SHARE this?\nretention_score /10: Watch to the END?\ntrend_score /10: Trending or searchable?\n\nTHUMBNAIL RULES: ONE focal point 40% of frame, dark bg #0A0A0F, lighting from below, strong emotion, MAX 3 words ALL CAPS, top or bottom position NEVER center.\nGenerate 3: A=Dramatic/Shocking B=Curiosity/Mystery C=Epic/Wide.\n\nReturn ONLY valid JSON with keys: topic, why_trending, hook_angle, visual_style, mood, content_type, target_audience, title, hook, open_loop, payoff_reveal, cliffhanger_ending, cta_line, post_watch_emotion, script_segments (array with: text, caption, visual_prompt, micro_cliffhanger, is_payoff), voiceover_full, ai_video_prompts, pexels_search_terms, description, tags, chapters (array: time, label), thumbnail_prompt, thumbnail_prompt_b, thumbnail_prompt_c, thumbnail_text, thumbnail_text_position, estimated_duration, south_asian_content, quality_score (hook_score, viral_score, retention_score, trend_score, total, passed)';

try {
  const https = require('https');
  const body = JSON.stringify({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 5000,
    system: systemPrompt,
    messages: [{ role: 'user', content: userPrompt }]
  });

  const data = await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.anthropic.com',
      path: '/v1/messages',
      method: 'POST',
      headers: {
        'x-api-key': ANT_KEY,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json',
        'content-length': Buffer.byteLength(body)
      }
    }, res => {
      let raw = '';
      res.on('data', c => raw += c);
