const status = (item && item.status) || "";
const url = (item && (item.url || item.snapshot_url)) || "";
const renderId = (item && item.id) || "";

// SUCCESS: render finished
if (status === "succeeded" && url) {
  stored.renderRetryCount = 0;
  return [{ json: { ...item, url, renderDone: true, title: metaTitle || scriptMeta.title || "", hook: scriptMeta.hook || "" } }];
}

// HARD FAIL: Creatomate reported failure
if (status === "failed") {
  stored.renderRetryCount = 0;
  const errMsg = (item && item.error_message) || "Render failed";
  return [{ json: { error: true, errorMsg: "Render failed: " + errMsg, renderId, renderDone: true, title: scriptMeta.title || "", hook: scriptMeta.hook || "" } }];
}

// TIMEOUT: too many retries - set renderDone:true so IF node exits loop
const retryCount = (stored.renderRetryCount || 0) + 1;
stored.renderRetryCount = retryCount;

if (retryCount >= 6) {
  stored.renderRetryCount = 0;
  return [{ json: { error: true, errorMsg: "Render timed out after " + (retryCount - 1) + " retries (9+ mins). Last status: " + status, renderId, renderDone: true, title: scriptMeta.title || "", hook: scriptMeta.hook || "" } }];
}

// STILL PROCESSING: renderDone:false so IF node loops back to Wait 90s
return [{ json: { ...(item || {}), renderDone: false, retryCount, renderId, renderStatus: status, title: scriptMeta.title || "", hook: scriptMeta.hook || "" } }];

